using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiFetchTool
{
    [McpServerTool(Name = "fetch_post"), Description("Fetches a post by ID from the external API.")]
    public static async Task<string> FetchPost(
        IHttpClientFactory httpClientFactory,
        [Description("The numeric ID of the post to retrieve.")] int postId)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync($"/posts/{postId}");
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync();
    }
}

using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizationPrompts
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a summarization prompt for the given text.")]
    public static IEnumerable<ChatMessage> Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Maximum number of sentences in the summary.")] int? maxSentences = null)
    {
        var constraint = maxSentences.HasValue
            ? $" Use no more than {maxSentences.Value} sentences."
            : string.Empty;

        return
        [
            new ChatMessage(ChatRole.User,
                $"Please provide a concise summary of the following text.{constraint}\n\n{text}")
        ];
    }
}

